parameters.jsCode:
const j = $input.first().json;
const protocolId = 'SP-' + String(Math.floor(10000 + Math.random() * 90000));
return [{
  json: {
    protocolId,
    clientCode: j['Client Code'],
    ageRange: j['Age Range'],
    sex: j['Sex'],
    symptoms: j['Key Symptoms'],
    labs: j['Relevant Labs (functional ranges)'] || 'None provided',
    medications: j['Current Medications'] || 'None reported',
    goals: j['Health Goals'],
    dietaryRestrictions: j['Dietary Restrictions'] || 'None reported',
    submissionDate: new Date().toISOString().slice(0, 10)
  }
}];

